INSERT INTO `list_sdki` (`id`, `nomor_sdki`, `diagnosa_sdki`, `penyebab_sdki`, `mayor_subjektif`, `mayor_objektif`, `minor_subjektif`, `minor_objektif`, `created_at`, `updated_at`, `deleted_at`) VALUES
	('51d12ff4-07e3-11f1-8f82-0200ca9b8436', 'D.0001', 'Bersihan Jalan Napas Tidak Efektif', 'Penyebab fisiologis\n- Spasme jalan napas\n- Hipersekresi jalan napas\n- Disfungsi neuromuskuler\n- Benda asing dalam jalan napas\n- Adanya jalan napas buatan\n- Sekresi yang tertahan\n- Hiperplasia dinding jalan napas\n- Proses infeksi\n- Respon alergi\n- Efek agen farmakologis\nPenyebab situasional\n- Merokok aktif\n- Merokok pasif\n- Terpajan polutan', '(tidak tersedia)', '- Batuk tidak efektif atau tidak mampu batuk\n- Sputum berlebih / obstruksi di jalan napas\n- Mengi, wheezing dan/atau ronkhi kering', '- Dispnea\n- Sulit berbicara\n- Ortopnea', '- Gelisah\n- Sianosis\n- Bunyi napas menurun\n- Frekuensi napas berubah\n- Pola napas berubah', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d132a1-07e3-11f1-8f82-0200ca9b8436', 'D.0003', 'Gangguan Pertukaran Gas', '- Ketidakseimbangan ventilasi-perfusi\n- Perubahan membrane alveolus-kapiler', '- Dispnea', '- PCO2 meningkat/menurun\n- PO2 menurun\n- Takikardi\n- pH arteri meningkat/menurun\n- Bunyi napas tambahan', '- Pusing\n- Penglihatan kabur', '- Sianosis\n- Diaphoresis\n- Gelisah\n- Napas cuping hidung\n- Pola napas abnormal (cepat/lambat, regular/ireguler, dalam/dangkal)\n- Warna kulit abnormal (mis. pucat, kebiruan)\n- Kesadaran menurun', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d13448-07e3-11f1-8f82-0200ca9b8436', 'D.0004', 'Gangguan Ventilasi Spontan', '- Gangguan metabolisme\n- Kelemahan otot pernapasan', '- Dispnea', '- Peningkatan otot bantu napas meningkat\n- Volume tidal menurun\n- PCO2 meningkat\n- PO2 menurun\n- SaO2 menurun', '(tidak tersedia)', '- Gelisah\n- Takikardi', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d13520-07e3-11f1-8f82-0200ca9b8436', 'D.0005', 'Pola Napas Tidak Efektif', '- Depresi pusat pernapasan\n- Hambatan upaya napas (mis. nyeri saat bernapas, kelemahan otot pernapasan)\n- Deformitas dinding dada\n- Deformitas tulang dada\n- Gangguan neuromuskular\n- Gangguan neurologis (mis. elektroensefalogram [EEG] positif, cedera kepala, gangguan kejang)\n- Imaturitas neurologis\n- Penurunan energi\n- Obesitas\n- Posisi tubuh yang menghambat ekspansi paru\n- Sindrom hipoventilasi\n- Kerusakan inervasi diafragma (kerusakan saraf C5 ke atas)\n- Cedera pada medulla spinalis\n- Efek agen farmakologis\n- Kecemasan', '- Dispnea', '- Penggunaan otot bantu pernapasan\n- Fase ekspirasi memanjang\n- Pola napas abnormal (mis. takipnea, bradypnea, hiperventilasi, Kussmaul, Cheyne-stokes)', '- Ortopnea', '- Pernapasan pursed-lip\n- Pernapasan cuping hidung\n- Diameter thoraks anterior-posterior meningkat\n- Ventilasi semenit menurun\n- Kapasitas vital menurun\n- Tekanan ekspirasi menurun\n- Tekanan inspirasi menurun\n- Ekskursi dada berubah', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d135ed-07e3-11f1-8f82-0200ca9b8436', 'D.0007', 'Gangguan Sirkulasi Spontan', '- Abnormalitas kelistrikan jantung\n- Abnormalitas struktur jantung\n- Penurunan fumgsi ventrikel', '- Tidak berespon', '- Frekuensi nadi <50 kali/menit atau >150 kali/menit\n- Tekanan darah sistolik <60 mmHg atau >200 mmHg\n- Frekuensi napas <6 kali/menit atau >30 kali/menit\n- Kesadaran menurun atau tidak sadar', '(tidak tersedia)', '- Suhu tubuh <34,5Â°C\n- Tidak ada produksi urin dalam 6 jam\n- Saturasi oksigen <85%\n- Gambaran EKG menunjukkan aritmia letal (mis. VT, VF, Asistol, PEA)\n- Gambaran EKG menunjukkan aritmia mayor (mis. AV block derajat 2 tipe 2, AV block total, takiaritmia/ bradiaritmia, SVT, VES simtomatik)\n- ETCO2 < 35mmHg', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d136da-07e3-11f1-8f82-0200ca9b8436', 'D.0008', 'Penurunan Curah Jantung', '- Perubahan irama jantung\n- Perubahan frekuensi jantung\n- Perubahan kontraktilitas\n- Perubahan preload\n- Perubahan afterload', 'Perubahan irama jantung\n- Palpitasi\n\n\n\nPerubahan preload\n-        Lelah\n\n\n\n\n\nPerubahan afterload\n- Dispnea\n\n\n\n\n\nPerubahan kontraktilitas\n- Paroxysmal Nocturnal Dyspnea (PND)\n- Ortopnea\n- Batuk', 'Perubahan irama jantung\n- Bradikardia/ takikardia\n- Gambaran EKG aritmia atau gangguan konduksi\n\nPerubahan preload\n- Edema\n- Distensi vena jugularis\n- Central Venous Pressure  (CVP) meningkat/ menurun\n\n\nPerubahan afterload\n- Tekanan darah meningkat / menurun\n- Nadi perifer teraba lemah\n- CRT >3 detik\n- Oliguria\n- Warna kulit pucat dan/atau sianosis\nPerubahan kontraktilitas\n- Terdengar suara jantung S3 dan/atau S4\n- Ejection Fraction (EF) menurun', 'Perubahan preload\n(tidak tersedia)\n\n\n\n\nPerubahan afterload\n(tidak tersedia)\n\n\n\n\n\nPerubahan kontraktilitas\n(tidak tersedia)\n\n\n\n\n\nPerilaku / emosional\n- Cemas\n- Gelisah', 'Perubahan preload\n- Murmur jantung\n- Berat badan bertambah\n- Pulmonary Artery Wedge Pressure (PAWP) menurun\nPerubahan afterload\n- Pulmonary Vascular Resistance (PVR) meningkat/ menurun\n- Systemic Vascular Resistance (SVR) meningkat/ menurun\n- Hepatomegali\nPerubahan kontraktilitas\n- Cardiac Index (CI) menurun\n- Left Ventricular Stroke Work Index (LVSWI) menurun\n- Stroke Volume Index (SVI) menurun\nPerilaku / emosional\n(tidak tersedia)', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d13797-07e3-11f1-8f82-0200ca9b8436', 'D.0009', 'Perfusi Perifer Tidak Efektif', '- Hiperglikemia\n- Penurunan konsentrasi hemoglobin\n- Peningkatan tekanan darah\n- Kekurangan volume cairan\n- Penurunan aliran arteri dan/atau vena\n- Kurang terpapar informasi tentang factor pemberat\n- Kurang terpapar informasi tentang proses penyakit\n- Kurang aktivitas fisik', '(tidak tersedia)', '- Pengisian kapiler >3 detik\n- Nadi perifer menurun atau tidak teraba\n- Akral teraba dingin\n- Warna kulit pucat\n- Turgor kulit menuru', '- Parastesia\n- Nyeri ekstermitas (klaudikasi intermiten)', '- Edema\n- Penyembuhan luka lambat\n- Indeks ankle-brachial <0,90\n- Bruit femoralis', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d13833-07e3-11f1-8f82-0200ca9b8436', 'D.0011', 'Risiko Penurunan Curah Jantung', '- Perubahan afterload\n- Perubahan frekuensi jantung\n- Perubahan irama jantung\n- Perubahan kontraktilitas\n- Perubahan preload', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d138da-07e3-11f1-8f82-0200ca9b8436', 'D.0012', 'Risiko Perdarahan', '- Aneurisma\n- Gangguan gastrointestinal\n- Gangguan fungsi hati\n- Komplikasi kehamilan\n- Komplikasi pasca partum\n- Gangguan koagulasi\n- Efek agen farmakologis\n- Tindakan pembedahan\n- Trauma\n- Kurang terpapar informasi tentang pencegahan perdarahan\n- Proses keganasan', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d139d1-07e3-11f1-8f82-0200ca9b8436', 'D.0016', 'Risiko Perfusi Renal Tidak Efektif', '- Kekurangan volume cairan\n- Embolisme vaskuler\n- Vaskulitis\n- Hipertensi\n- Disfungsi ginjal\n- Hiperglikemia\n- Keganasan\n- Pembedahan jantung\n- Bypass kardiopulmonal\n- Hipoksemia\n- Hipoksia\n- Asidosis metabolik\n- Trauma\n- Sindrom kompartemen abdomen\n- Luka bakar\n- Sepsis\n- Sindrom respon inflamasi sistemik\n- Lanjut usia\n- Merokok\n- Penyalahgunaan zat', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d13b1e-07e3-11f1-8f82-0200ca9b8436', 'D.0017', 'Risiko Perfusi Serebral Tidak Efektif', '- Keabnormalan masa protrombin dan/atau masa protrombin parsial\n- Penurunan kinerja ventrikel kiri\n- Aterosklerosis aorta\n- Diseksi arteri\n- Fibrilasi atrium\n- Tumor otak\n- Stenosis karotis\n- Miksoma atrium\n- Aneurisma serebri\n- Koagulopati (misalnya anemia sel sabit)\n- Dilatasi kardiomiopati\n- Koagulasi intravaskuler diseminata\n- Embolisme\n- Cidera kepala\n- Hiperkolesteronemia\n- Hipertensi\n- Endokarditis infektif\n- Katup prostetik mekanis\n- Stenosis mitral\n- Neoplasma otak\n- Infark miokard akut\n- Sindrom sick sinus\n- Penyalahgunaan zat\n- Terapi trombolitik\n- Efek samping tindakan', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d13bd4-07e3-11f1-8f82-0200ca9b8436', 'D.0019', 'Defisit Nutrisi', '- Kurangnya asupan makanan\n- Ketidakmampuan menelan makanan\n- Ketidakmampuan mencerna makanan\n- Ketidakmampuan mengabsorbsi nutrien\n- Peningkatan kebutuhan metabolisme\n- Faktor ekonomi (mis: finansial tidak mencukupi)\n- Faktor psikologis (mis:  stres, keengganan untuk makan)', '(tidak tersedia)', '- Berat badan menurun minimal 10% dibawah rentang ideal', '- Cepat kenyang setelah makan\n- Kram/ nyeri abdomen\n- Nafsu makan menurun', '- Bising usus hiperaktif\n- Otot pengunyah lemah\n- Otot menelan lemah\n- Membran mukosa pucat\n- Sariawan\n- Serum albumin turun\n- Rambut rontok berlebihan\n- Diare', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d13c98-07e3-11f1-8f82-0200ca9b8436', 'D.0020', 'Diare', 'Penyebab fisiologis\n- Inflamasi gastrointestinal\n- Iritasi gastrointestinal\n- Proses infeksi\n- Malabsorpsi\nPenyebab psikologis\n- Kecemasan \n- Tingkat stres tinggi \nPenyebab situasional\n- Terpapar kontaminan \n- Terpapar toksin \n- Penyalahgunaan laksatif\n- Penyalahgunaan zat\n- Program pengobatan (agen tiroid, analgesik, pelunak feses, ferosulfat, antasida, cimetidine, dan antibiotik)\n- Perubahan air dan makanan\n- Bakteri pada air', '(tidak tersedia)', '- Defekasi lebih dari tiga kali dalam 24 jam\n- Feses lembek dan cair', '- Urgency\n- Nyeri / kram abdomen', '- Frekuensi peristaltik meningkat\n- Bising usus hiperaktif', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d13d3f-07e3-11f1-8f82-0200ca9b8436', 'D.0023', 'Hipovolemia', '- Kehilangan cairan aktif\n- Kegagalan mekanisme regulasi\n- Peningkatan permeabilitas kapiler\n- Kekurangan intake cairan\n- Evaporasi', '(tidak tersedia)', '- Frekuensi nadi meningkat\n- Nadi teraba lemah\n- Tekanan darah menurun\n- Tekanan nadi menyempit\n- Turgor kulit menurun\n- Membran mukosa kering\n- Volume urin menurun\n- Hematokrit meningkat', '- Merasa lemah\n- Mengeluh haus', '- Pengisian vena menurun\n- Status mental berubah\n- Suhu tubuh meningkat\n- Konsentrasi urin meningkat\n- Berat badan turun tiba-tiba', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d13dfb-07e3-11f1-8f82-0200ca9b8436', 'D.0027', 'Ketidakstabilan Kadar Glukosa Darah', 'Hiperglikemia\n- Disfungsi pankreas\n- Resistensi insulin\n- Gangguan toleransi glukosa darah\n- Gangguan glukosa darah puasa\n\nHipoglikemia\n- Penggunaan insulin atau obat glikemik oral\n-Hiperinsulinemia (mis. insulinoma)\n- Endokrinopati (mis. kerusakan adrenal atau pituitari)\n- Disfungsi hati\n- Disfungsi ginjal kronis\n- Efek agen farmakologis\n- TIndakan pembedahan neoplasma\n- Gangguan metabolik bawaan (mis. gangguan penyimpanan lisosomal, galaktosemia, gangguan penyimpanan glikogen)', 'Hipoglikemia\n- Mengantuk\n- Pusing\n\n\n\nHiperglikemia\n- Lelah atau lesu', 'Hipoglikemia\n- Gangguan koordinasi\n- Kadar glukosa dalam darah/ urin rendah\n\n\n\nHiperglikemia\n- Kadar glukosa dalam darah/ urin tinggi', 'Hipoglikemia\n- Palpitasi\n- Mengeluh lapar\n\n\n\nHiperglikemia\n- Mulut kering\n- Haus meningkat', 'Hipoglikemia\n- Gemetar\n- Kesadaran menurun\n- Perilaku aneh\n- Sulit bicara\n- Berkeringat\n\nHiperglikemia\n- Jumlah urin meningkat', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d13ea1-07e3-11f1-8f82-0200ca9b8436', 'D.0032', 'Risiko Defisit Nutrisi', '- Ketidakmampuan menelan makanan\n- Ketidakmampuan mencerna makanan\n- Ketidakmampuan mengabsorbsi nutrien\n- Peningkatan kebutuhan metabolisme\n- Faktor ekonomi (mis: finansial tidak mencukupi)\n- Faktor psikologis (mis:  stres, keengganan untuk makan)', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d13f59-07e3-11f1-8f82-0200ca9b8436', 'D.0034', 'Risiko Hipovolemia', '- Kehilangan cairan secara aktif\n- Gangguan absorpsi cairan\n- Usia lanjut\n- Kelebihan berat badan\n- Status hipermetabolik\n- Kegagalan mekanisme regulasi\n- Evaporasi\n- Kekurangan intake cairan\n- Efek agen farmakologis', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d14001-07e3-11f1-8f82-0200ca9b8436', 'D.0036', 'Risiko Ketidakseimangan Cairan', '- Prosedur pembedahan mayor\n- Trauma/perdarahan\n- Luka bakar\n- Aferesis\n- Asites\n- Obstruksi intestinal\n- Peradangan pancreas\n- Penyakit ginjal dan kelenjar\n- Disfungsi intestinal', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1409d-07e3-11f1-8f82-0200ca9b8436', 'D.0037', 'Risiko Ketidakseimbangan Elektrolit', '- Ketidakseimbangan cairan (mis: dehidrasi dan intoksikasi air)\n- Kelebihan volume cairan\n- Gangguan mekanisme regulasi (mis: diabetes)\n- Efek samping prosedur (mis: pembedahan)\n- Diare\n- Muntah\n- Disfungsi ginjal\n- Disfungsi regulasi endokrin', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d14138-07e3-11f1-8f82-0200ca9b8436', 'D.0038', 'Risiko Ketidakstabilan Kadar Glukosa Darah', '- Kurang terpapar informasi tentang manajemen diabetes\n- Ketidaktepatan pemantauan glukosa darah\n- Kurang patuh pada rencana manajemen diabetes\n- Manajemen medikasi tidak terkontrol\n- Kehamilan\n- Periode pertumbuhan cepat\n- Stress berlebihan\n- Penambahan berat badan\n- Kurang dapat menerima diagnosis', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d141d8-07e3-11f1-8f82-0200ca9b8436', 'D.0039', 'Risiko Syok', '- Hipoksemia\n- Hipoksia\n- Hipotensi\n- Kekurangan volume cairan\n- Sepsis\n- Sindrom respons inflamasi sistemik (systemic inflammatory response syndrome/SIRS)', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d14499-07e3-11f1-8f82-0200ca9b8436', 'D.0040', 'Gangguan Eliminasi Urin', '- Penurunan kapasitas kandung kemih\nI- ritasi kandung kemih\n- Penurunan kemampuan menyadari tanda-tanda gangguan kandung kemih\n- Efek tindakan medis dan diagnostik (mis. operasi ginjal, operasi saluran kemih, anestesi, dan obat-obatan)\n- Kelemahan otot pelvis\n- Ketidakmampuan mengakses toilet (mis. imobilisasi)\n- Hambatan lingkungan\n- Ketidakmampuan mengkomunikasikan kebutuhan eliminasi\n- Outlet kandung kemih tidak lengkap (mis. anomali saluran kemih kongenital)\n- Imaturitas (pada anak usia < 3 tahun)', '- Desakan berkemih (urgensi)\n- Urin menetes (dribbling)\n- Sering buang air kecil\n- Nocturia (buang air kecil pada malam hari)\n- Mengompol\n- Enuresis (tidak dapat menahan kencing)', '- Distensi kandung kemih\n- Berkemih tidak tuntas (hesistancy)\n- Volume residu urin meningkat', '(tidak tersedia)', '(tidak tersedia)', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1455a-07e3-11f1-8f82-0200ca9b8436', 'D.0049', 'Konstipasi', 'Penyebab fisiologis\n- Penurunan motilitas gastrointestinal\n- Ketidakadekuatan pertumbuhan gigi\n- Ketidakcukupan diet\n- Ketidakcukupan asupan serat\n- Ketidakcukupan asupan cairan\n- Aganglionik (mis: penyakit hircsprung)\n- Kelemahan otot abdomen\nPenyebab psikologis\n- Konfusi\n- Depresi\n- Gangguan emosional\nPenyebab situasional\n- Perubahan kebiasaan makan (mis: jenis makanan, jadwal makan)\n- Ketidakadekuatan toileting\n- Aktivitas fisik harian kurang dari yang dianjurkan\n- Penyalahgunaan laksatif\n- Efek agen farmakologis\n- Ketidakteraturan kebiasaan defekasi\n- Kebiasaan menahan dorongan defekasi\n- Perubahan lingkungan', '- Defekasi kurang dari 2 kali seminggu\n- Pengeluaran feses lama dan sulit', '- Feses keras\n- Peristaltik usus menurun', '- Mengejan saat defekasi', '- Distensi abdomen\n- Kelemahan umum\n- Teraba massa pada rektal', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1460e-07e3-11f1-8f82-0200ca9b8436', 'D.0050', 'Retensi Urin', '- Peningkatan tekanan uretra\n- Kerusakan arkus refleks\n- Blok sfingter\n- Disfungsi neurologis (mis: trauma, penyakit saraf)\n- Efek agen farmakologis (mis: atropine, belladonna, psikotropik, antihistamin, opiate)', '- Sensasi penuh pada kandung kemih', '- Disuria/anuria\n- Distensi kandung kemih', '- Dribbing', '- Inkontinensia berlebih\n- Residu urin 150 ml atau lebih', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d146c3-07e3-11f1-8f82-0200ca9b8436', 'D.0054', 'Gangguan Mobilitas Fisik', '- Kerusakan integritas struktur tulang\n- Perubahan metabolisme\n- Ketidakbugaran fisik\n- Penurunan kendali otot\n- Penurunan massa otot\n- Penurunan kekuatan otot\n- Keterlambatan perkembangan\n- Kekakuan sendi\n- Kontraktur\n- Malnutrisi\n- Gangguan musculoskeletal\n- Gangguan neuromuscular\n- Indeks masa tubuh diatas persentil ke-75 sesuai usia\n- Efek agen farmakologis\n- Program pembatasan gerak\n- Nyeri\n- Kurang terpapar informasi tentang aktivitas fisik\n- Kecemasan\n- Gangguan kognitif\n- Keengganan melakukan pergerakan\n- Gangguan sensori-persepsi', '- Mengeluh sulit menggerakkan ekstremitas', '- Kekuatan otot menurun\n- Rentang gerak (ROM) menurun', '- Nyeri saat bergerak\n- Enggan melakukan pergerakan\n- Merasa cemas saat bergerak', '- Sendi kaku\n- Gerakan tidak terkoordinasi\n- Gerakan terbatas\n- Fisik lemah', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1aefe-07e3-11f1-8f82-0200ca9b8436', 'D.0056', 'Intoleransi Aktivitas', '- Ketidakseimbangan antara suplai dan kebutuhan oksigen\n- Tirah baring\n- Kelemahan\n- Imobilitas\n- Gaya hidup monoton', '- Mengeluh lelah', '- Frekuensi jantung meningkat > 20% dari kondisi istirahat', '- Dispnea saat/ setelah aktivitas\n- Merasa tidak nyaman setelah beraktivitas\n- Merasa lemah', '- Tekanan darah berubah >20% dari kondisi istirahat\n- Gambaran EKG menunjukkan aritmia saat/ setelah aktivitas\n- Gambaran EKG menunjjukkan iskemia\n- Sianosis', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1b00a-07e3-11f1-8f82-0200ca9b8436', 'D.0057', 'Keletihan', '- Gangguan tidur\n- Gaya hidup monoton\n- Kondisi fisiologis (mis. penyakit kronis, penyakit terminal, anemia. malnutrisi, kehamilan) â€˜\n- Program perawatan/pengobatan jangka panjang\n- Peristiwa hidup negatif\n- Stres berlebihan\n- Depresi', '- Merasa energi tidak putih walaupun telah tidur\n- Merasa kurang tidur\n- Mengeluh lelah', '- Tidak mampu mempertahankan aktivitas rutin\n- Tampak lesu', '- Merasa bersalah akibat tidak mampu menjalankan tanggung jawab\n- Libido menurun', '- Kebutuhan istirahat meningkat', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1b0d9-07e3-11f1-8f82-0200ca9b8436', 'D.0062', 'Gangguan Memori', '- Ketidakadekuatan stimulasi intelektual\n- Gangguan sirkulasi ke otak\n- Gangguan volume cairan dan/atau elektrolit\n- Proses penuaan\n- Hipoksia\n- Gangguan neurologis (mis: EEG positif, cidera kepala, gangguan kejang)\n- Efek agen farmakologis\n- Penyalahgunaan zat\n- Faktor psikologis (mis: kecemasan, depresi, stress berlebihan, berduka, gangguan tidur)\n- Distraksi lingkungan', '- Melaporkan pernah mengalami pengalaman lupa\n- Tidak mampu mempelajari keterampilan baru\n- Tidak mampu mengingat informasi faktual\n- Tidak mampu mengingat perilaku tertentu yang pernah dilakukan\n- Tidak mampu mengingat peristiwa', '- Tidak mampu melakukan kemampuan yang dipelajari sebelumnya', '- Lupa melakukan perilaku pada waktu yang telah dijadwalkan\n- Merasa mudah lupa', '(tidak tersedia)', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1b19d-07e3-11f1-8f82-0200ca9b8436', 'D.0064', 'Konfusi Akut', '- Delirium\n- Demensia\n- Fluktuasi siklus tidur-bangun\n- Usia lebih dari 60 tahun\n- Penyalahgunaan zat', '- Kurang motivasi untuk memulai/menyelesaikan perilaku berorientasi tujuan\n- Kurang motivasi untuk memulai/menyelesaikan perilaku terarah', '- Fluktuasi fungsi kognitif\n- Fluktuasi tingkat kesadaran\n- Fluktuasi aktivitas psikomotorik', '- Salah persepsi', '- Halusinasi\n- Gelisah', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1b24f-07e3-11f1-8f82-0200ca9b8436', 'D.0065', 'Konfusi Kronis', '- Cedera otak (mis: kerusakan kardiovaskular, penyakit neurologis, trauma, tumor)\n- Psikosis Korsakoff\n- Demensia multi infark', '- Kurang motivasi untuk memulai/menyelesaikan perilaku berorientasi tujuan\n- Kurang motivasi untuk memulai/menyelesaikan perilaku terarah', '- Fungsi kognitif berubah progresif\n- Memori jangka pendek dan/atau Panjang berubah\n- Interpretasi berubah\n- Fungsi sosial terganggu\n- Respon terhadap stimulus berubah', '- Salah persepsi', '- Gangguan otak organik', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1b2fb-07e3-11f1-8f82-0200ca9b8436', 'D.0074', 'Gangguan Rasa Nyaman', '- Gejala penyakit\n- Kurang pengendalian situasional/lingkungan\n- Ketidakadekuatan sumber daya (mis: dukungan finansial, sosial, dan pengetahuan)\n- Kurangnya privasi\n- Gangguan stimulus lingkungan\n- Efek samping terapi (mis: medikasi, radiasi, kemoterapi)\n- Gangguan adaptasi kehamilan', '- Mengeluh tidak nyaman', '- Gelisah', '- Mengeluh sulit tidur\n- Tidak mampu rileks\n- Mengeluh kedinginan/ kepanasan\n- Merasa gatal\n- Mengeluh mual\n- Mengeluh lelah', '- Menunjukkan gejala distres\n- Tampak merintih/ menangis\n- Pola eliminasi berubah\n- Postur tubuh berubah\n- Iritabilitas', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1b3b3-07e3-11f1-8f82-0200ca9b8436', 'D.0076', 'Nausea', '- Gangguan biokimiawi (mis: uremia, ketoasidosis diabetic)\n- Gangguan pada esofagus\n- Distensi lambung\n- Iritasi lambung\n- Gangguan pankreas\n- Peregangan kapsul limpa\n- Tumor terlokalisasi (mis: neuroma akustik, tumor otak primer atau sekunder, metastasis tulang di dasar tengkorak)\n- Peningkatan tekanan intraabdominal (mis: keganasan intraabdomen)\n- Peningkatan tekanan intrakranial\n- Peningkatan tekanan intraorbital (mis: glaukoma)\n- Mabuk perjalanan\n- Kehamilan\n- Aroma tidak sedap\n- Rasa makanan/minuman yang tidak enak\n- Stimulus penglihatan tidak menyenangkan\n- Faktor psikologis (mis: kecemasan, ketakutan, stres)\n- Efek agen farmakologis\n- Efek toksin', '- Mengeluh mual\n- Merasa ingin muntah\n- Tidak berminat makan', '(tidak tersedia)', '- Merasa asam di mulut\n- Sensasi panas/ dingin\n- Sering menelan', '- Saliva meningkat\n- Pucat\n- Diaforesis\n- Takikardia\n- Pupil dilatasi', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1b466-07e3-11f1-8f82-0200ca9b8436', 'D.0077', 'Nyeri Akut', '- Agen pencedera fisiologis (mis: inflamasi, iskemia, neoplasma)\n- Agen pencedera kimiawi (mis: terbakar, bahan kimia iritan)\n- Agen pencedera fisik (mis: abses, amputasi, terbakar, terpotong, mengangkat berat, prosedur operasi, trauma, latihan fisik berlebihan)', '- Mengeluh nyeri', '- Tampak meringis\n- Bersikap protektif (mis: waspada, posisi menghindari nyeri)\n- Gelisah\n- Frekuensi nadi meningkat\n- Sulit tidur', '(tidak tersedia)', '- Tekanan darah meningkat\n- Pola napas berubah\n- Nafsu makan berubah\n- Proses berpikir terganggu\n- Menarik diri\n- Berfokus pada diri sendiri\n- Diaforesis', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1b775-07e3-11f1-8f82-0200ca9b8436', 'D.0078', 'Nyeri Kronis', '- Kondisi muskuloskeletal kronis\n- Kerusakan sistem saraf\n- Penekanan saraf\n- Infiltrasi tumor\n- Ketidakseimbangan neurotransmiter, neuromodulator, dan reseptor\n- Gangguan imunitas (mis: neuropati terkait HIV, virus varicella-zoster)\n- Gangguan fungsi metabolik\n- Riwayat posisi kerja statis\n- Peningkatan indeks massa tubuh\n- Kondisi pasca trauma\n- Tekanan emosional\n- Riwayat penganiayaan (mis: fisik, psikologis, seksual)\n- Riwayat penyalahgunaan obat/zat', '- Mengeluh nyeri\n- Merasa depresi (tertekan)', '- Tampak meringis\n- Gelisah\n- Tidak mampu menuntaskan aktivitas', '- Merasa takut mengalami cedera berulang', '- Bersikap protektif (mis. posisi menghindari nyeri)\n- Waspada\n- Pola tidur berubah\n- Anoreksia\n- Fokus menyempit\n- Berfokus pada diri sendiri', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1b968-07e3-11f1-8f82-0200ca9b8436', 'D.0080', 'Ansietas', '- Krisis situasional\n- Kebutuhan tidak terpenuhi\n- Krisis maturasional\n- Ancaman terhadap konsep diri\n- Ancaman terhadap kematian\n- Kekhawatiran mengalami kegagalan\n- Disfungsi sistem keluarga\n- Hubungan orang tua-anak tidak memuaskan\n- Faktor keturunan (temperamen mudah teragitasi sejak lahir)\n- Penyalahgunaan zat\n- Terpapar bahaya lingkungan (mis: toksin, polutan, dan lain-lain)\n- Kurang terpapar informasi', '- Merasa bingung\n- Merasa khawatir dengan akibat dari kondisi yang dihadapi\n- Sulit berkonsentasi', '- Tampak gelisah\n- Tampak tegang\n- Sulit tidur', '- Mengeluh pusing\n- Anoreksia\n- Palpitasi\n- Merasa tidak berdaya', '- Frekuensi napas meningkat\n- Frekuensi nadi meningkat\n- Tekanan darah meningkat\n- Diaforesis\n- Tremor\n- Muka tampak pucat\n- Suara bergetar\n- Kontak mata buruk\n- Sering berkemih\n- Berorientasi pada masa lalu', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1ba33-07e3-11f1-8f82-0200ca9b8436', 'D.0096', 'Koping Tidak Efektif', '- Ketidakpercayaan terhadap kemampuan diri mengatasi masalah\n- Ketidakadekuatan sistem pendukung\n- Ketidakadekuatan strategi koping\n- Ketidakteraturan atau kekacauan lingkungan\n- Ketidakcukupan persiapan untuk menghadapi stresor\n- Disfungsi sistem keluarga\n- Krisis situasional\n- Krisis maturasional\n- Kerentanan personalitas\n- Ketidakpastian', '- Mengungkapkan tidak mampu mengatasi masalah', '- Tidak mampu memenuhi peran yang diharapkan (sesuai usia)\n- Menggunakan mekanisme koping yang tidak sesuai', '- Tidak mampu memenuhi kebutuhan dasar\n- Kekhawatiran kronis', '- Penyalahgunaan zat\n- Memanipulasi orang lain untuk memenuhi keinginannya sendiri\n- Perilaku tidak asertif\n- Partisipasi sosial kurang', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d1baee-07e3-11f1-8f82-0200ca9b8436', 'D.0105', 'Waham', '- Faktor biologis: kelainan genetik/keturunan, kelainan neurologis (mis: gangguan sistem limbik, gangguan ganglia basalis, tumor otak)\n- Faktor psikodinamik (mis: isolasi sosial, hipersensitif)\n- Maladaptasi\n- Stres berlebihan', '- Mengungkapkan isi waham', '- Menunjukkan perilaku sesuai isi waham\n- Isi pikir tidak sesuai realitas\n- Isi pembicaraan sulit dimengerti', '- Merasa sulit berkonsentrasi\n- Merasa khawatir', '- Curiga berlebihan\n- Waspada berlebihan\n- Bicara berlebihan\n- Sikap menentang atau permusuhan\n- Wajah tegang\n- Pola tidur berubah\n- Tidak mampu mengambil keputusan\n- Flight of idea\n- Produktifitas kerja menurun\n- Tidak mampu merawat diri\n- Menarik diri', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d230b2-07e3-11f1-8f82-0200ca9b8436', 'D.0111', 'Defisit Pengetahuan', '- Keterbatasan kognitif\n- Gangguan fungsi kognitif\n- Kekeliruan mengikuti anjuran\n- Kurang terpapar informasi\n- Kurang minat dalam belajar\n- Kurang mampu mengingat\n- Ketidaktahuan menemukan sumber informasi', '- Menanyakan masalah yang dihadapi', '- Menunjukkan perilaku tidak sesuai anjuran\n- Menunjukkan persepsi yang keliru terhadap masalah', '(tidak tersedia)', '- Menjalani pemeriksaan yang tidak tepat\n- Menunjukkan perilaku berlebihan (mis. apatis, bermusuhan, agitasi, histeria)', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d231a5-07e3-11f1-8f82-0200ca9b8436', 'D.0118', 'Gangguan Interaksi Sosial', '- Defisiensi bicara\n- Hambatan perkembangan/maturase\n- Ketiadaan orang terdekat\n- Perubahan neurologis (mis: kelahiran prematur, distres fetal, persalinan cepat, atau persalinan lama)\n- Disfungsi sistem keluarga\n- Ketidakteraturan atau kekacauan lingkungan\n- Penganiayaan atau pengabaian anak\n- Hubungan orang tua-anak tidak memuaskan\n- Model peran negatif\nImpulsif\n- Perilaku menentang\n- Perilaku agresif\n- Keengganan berpisah dengan orang terdekat', '- Merasa tidak nyaman dengan situasi sosial\n- Merasa sulit menerima atau mengkomunikasikan perasaan', '- Kurang responsif atau tertarik pada orang lain\n- Tidak berminat melakukan kontak emosi dan fisik', '- Sulit mengungkapkan kasih sayang', '- Gejala cemas berat\n- Kontak mata kurang\n- Ekspresi wajah tidka responsif\n- Tidak kooperatif dalam bermain dan berteman dengan sebaya\n- Perilaku tidak sesuai usia', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d23258-07e3-11f1-8f82-0200ca9b8436', 'D.0121', 'Isolasi Sosial', '- Keterlambatan perkembangan\n- Ketidakmampuan menjalin hubungan yang memuaskan\n- Ketidaksesuaian minat dengan tahap perkembangan\n- Ketidaksesuaian nilai-nilai dengan norma\n- Ketidaksesuaian perilaku sosial dengan norma\n- Perubahan penampilan fisik\n- Perubahan status mental\n- Ketidakadekuatan sumber daya personal (mis: disfungsi berduka, pengendalian diri buruk)', '- Merasa ingin sendirian\n- Merasa tidak aman di tempat umum', '- Menarik diri\n- Tidak berminat/menolak berinteraksi dengan orang lain atau lingkungan', '- Merasa berbeda dengan orang lain\n- Merasa asyik dengan pikiran sendiri\n- Merasa tidak mempunyai tujuan yang jelas', '- Afek datar\n- Afek sedih\n- Riwayat ditolak\n- Menunjukkan permusuhan\n- Tidak mampu memenuhi harapan orang lain\n- Kondisi difabel\n- Tindakan tidak berarti\n- Tidak ad akontak  mata\n- perkembangan terlambat\n- Tidak bergairah/ lesu', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d23305-07e3-11f1-8f82-0200ca9b8436', 'D.0129', 'Gangguan Integritas Kulit/Jaringan', '- Perubahan sirkulasi\n- Perubahan status nutrisi (kelebihan atau kekurangan)\n- Kekurangan/kelebihan volume cairan\n- Penurunan mobilitas\n- Bahan kimia iritatif\n- Suhu lingkungan yang ekstrim\n- Faktor mekanis (mis: penekanan pada tonjolan tulang, gesekan) atau faktor elektris (elektrodiatermi, energi listrik bertegangan tinggi)\n- Efek samping terapi radiasi\n- Kelembaban\n- Proses penuaan\n- Neuropati perifer\n- Perubahan pigmentasi\n- Perubahan hormonal\n- Kurang terpapar informasi tentang upaya mempertahankan/melindungi integritas jaringan', NULL, '- Kerusakan jaringan dan/atau lapisan kulit', '(tidak tersedia)', '- Nyeri\n- Perdarahan\n- Kemerahan\n- Hematoma', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d233a8-07e3-11f1-8f82-0200ca9b8436', 'D.0130', 'Hipertermia', '- Dehidrasi\n- Terpapar lingkungan panas\n- Proses penyakit (mis: infeksi, kanker)\n- Ketidaksesuaian pakaian dengan suhu lingkungan\n- Peningkatan laju metabolisme\n- Respon trauma\n- Aktivitas berlebihan\n- Penggunaan inkubator', '(tidak tersedia)', '- Suhu tubuh diatas nilai normal', '(tidak tersedia)', '- Kulit merah\n- Kejang\n- Takikardi\n- Takipnea\n- Kulit terasa hangat', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d23442-07e3-11f1-8f82-0200ca9b8436', 'D.0131', 'Hipotermia', '- Kerusakan hipotalamus\n- Konsumsi alkohol\n- Berat badan ekstrim\n- Kekurangan lemak subkutan\n- Terpapar suhu lingkungan rendah\n- Malnutrisi\n- Pemakaian pakaian tipis\n- Penurunan laju metabolisme\n- Tidak beraktivitas\n- Transfer panas (mis: konduksi, konveksi, evaporasi, radiasi)\n- Trauma\n- Proses penuaan\n- Efek agen farmakologis\n- Kurang terpapar informasi tentang pencegahan hipotermia', '(tidak tersedia)', '- Kulit teraba dingin\n- Menggigil\n- Suhu tubuh dibawah nilai normal', '(tidak tersedia)', '- Akrosianosis\n- Bradikardi\n- Dasar kuku sianotik\n- Hipoglikemia\n- Hipoksia\n- Pengisian kapiler >3 detik\n- Konsumsi oksigen meningkat\n- Ventilasi menurun\n- Piloereksi\n- Takikardi\n- Vasokontriksi perifer\n- Kutis memorata (pada neonatus)', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d234dc-07e3-11f1-8f82-0200ca9b8436', 'D.0132', 'Perilaku Kekerasan', '- Ketidakmampuan mengendalikan dorongan marah\n- Stimulus lingkungan\n- Konflik interpersonal\n- Perubahan status mental\n- Putus obat\n- Penyalahgunaan zat/alkohol', '- Mengancam\n- Mengumpat dengan kata-kata kasar\n- Suara keras\n- Bicara', '- Menyerang orang lain\n- Melukai diri sendiri/orang lain\n- Merusak lingkungan\n- Perilaku agresif/amuk', '(tidak tersedia)', '- Mata melotot atau pandangan tajam\n- Tangan mengepal\n- Rahang mengatup\n- Wajah memerah\n- Postur tubuh kaku', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d23571-07e3-11f1-8f82-0200ca9b8436', 'D.0134', 'Risiko Alergi', '- Makanan (mis: alpukat, pisang, kiwi, kacang, makanan olahan laut, buah tropis, jamur)\n- Terpapar zat alergen (mis: zat kimia, agen farmakologis)\n- Terpapar alergen lingkungan (mis: debu, serbuk sari)\n- Sengatan serangga', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d23608-07e3-11f1-8f82-0200ca9b8436', 'D.0136', 'Risiko Cedera', 'Faktor risiko eksternal cedera:\n- Terpapar patogen\n- Terpapar zat kimia toksik\n- Terpapar agen nosokomial\n- Ketidakamanan transportasi\n\nFaktor risiko internal cedera:\n- Ketidaknormalan profil darah\n- Perubahan orientasi afektif\n- Perubahan sensasi\n- Disfungsi autoimun\n- Disfungsi biokimia\n- Hipoksia jaringan\n- Kegagalan mekanisme pertahanan tubuh\n- Malnutrisi\n- Perubahan fungsi psikomotor\n- Perubahan fungsi kognitif', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d2369e-07e3-11f1-8f82-0200ca9b8436', 'D.0137', 'Risiko Cedera Pada Ibu', '- Besarnya ukuran janin\n- Malposisi janin (posisi posterior)\n- Induksi persalinan\n- Persalinan lama kala I, II, dan III\n- Disfungsi uterus\n- Efek metode/intervensi bedah selama persalinan\n- Kurangnya dukungan keluarga dan orang tua\n- Kurang adekuatnya observasi dan antisipasi\n- Keterlambatan pengambilan keputusan dan manajemen\n- Skrining dan perawatan prenatal yang tidak adekuat\n- Kecemasan berlebihan pada proses persalinan\n- Riwayat cedera pada persalinan sebelumnya\n- Usia ibu (< 15 tahun atau > 35 tahun)\n- Paritas banyak\n- Perubahan hormonal\n- Perubahan postur tubuh\n- Ketuban pecah\n- Proses infeksi\n- Penyakit penyerta\n- Masalah kontraksi', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d237d4-07e3-11f1-8f82-0200ca9b8436', 'D.0138', 'Risiko Cedera Pada Janin', '- Besarnya ukuran janin\n- Malposisi janin (posisi posterior)\n- Induksi persalinan\n- Persalinan lama kala I, II, dan III\n- Disfungsi uterus\n- Kecemasan yang berlebihan tentang proses persalinan\n- Riwayat persalinan sebelumnya\n- Usia ibu (< 15 tahun atau > 35 tahun)\n- Paritas banyak\n- Efek metode/intervensi bedah selama persalinan\n- Nyeri pada abdomen\n- Nyeri pada jalan lahir\n- Penggunaan alat bantu persalinan\n- Kelelahan\n- Merokok\n- Efek agen farmakologis\n- Pengaruh budaya\n- Pola makan yang tidak sehat\n- Faktor ekonomi\n- Konsumsi alkohol\n- Terpapar zat teratogen', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d2387b-07e3-11f1-8f82-0200ca9b8436', 'D.0140', 'Risiko Hipotermia', '- Berat badan ekstrem\n- Kerusakan hipotalamus\n- Konsumsi alkohol\n- Kurangnya lapisan lemak subkutan\n- Suhu lingkungan rendah\n- Malnutrisi\n- Pemakaian pakaian yang tipis\n- Penurunan laju metabolisme\n- Terapi radiasi\n- Tidak beraktivitas\n- Transfer panas (mis: konduksi, konveksi, evaporasi, radiasi)\n- Trauma\n- Prematuritas\n- Penuaan\n- Bayi baru lahir\n- Berat badan lahir rendah\n- Kurang terpapar informasi tentang pencegahan hipotermia\n- Efek agen farmakologis', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d23913-07e3-11f1-8f82-0200ca9b8436', 'D.0142', 'Risiko Infeksi', '- Penyakit kronis (mis: diabetes melitus)\n- Efek prosedur invasif\n- Malnutrisi\n- Peningkatan paparan organisme patogen lingkungan\n- Ketidakadekuatan pertahanan tubuh primer (gangguan peristaltik; kerusakan integritas kulit; perubahan sekresi pH; penurunan kerja siliaris; ketuban pecah lama; ketuban pecah sebelum waktunya; merokok; statis cairan tubuh)\n- Ketidakadekuatan pertahanan tubuh sekunder (penurunan hemoglobin; imunosupresi; leukopenia; supresi respon inflamasi; vaksinasi tidak adekuat)', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d239a7-07e3-11f1-8f82-0200ca9b8436', 'D.0143', 'Risiko Jatuh', '- Usia â‰¥  65 tahun (pada dewasa) atau â‰¤ 2 tahun (pada anak)\n- Riwayat jatuh\n- Anggota gerak bawah prosthesis (buatan)\n- Penggunaan alat bantu berjalan\n- Penurunan tingkat kesadaran\n- Perubahan fungsi kognitif\n- Lingkungan tidak aman (mis: licin, gelap, lingkungan asing)\n- Kondisi pasca operasi\n- Hipotensi ortostatik\n- Perubahan kadar glukosa darah\n- Anemia\n- Kekuatan otot menurun\n- Gangguan pendengaran\n- Gangguan keseimbangan\n- Gangguan penglihatan (mis: glaucoma, katarak, ablasio retina, neuritis optikus)\n- Neuropati\n- Efek agen farmakologis (mis: sedasi, alkohol, anestesi umum)', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d23a3e-07e3-11f1-8f82-0200ca9b8436', 'D.0148', 'Risiko Termoregulasi Tidak Efektif', '- Cedera otak akut\n- Dehidrasi\n- Pakaian yang tidak sesuai untuk suhu lingkungan\n- Peningkatan area permukaan tubuh terhadap rasio berat badan\n- Kebutuhan oksigen meningkat\n- Perubahan laju metabolisme\n- Proses penyakit (mis: infeksi)\n- Suhu lingkungan ekstrem\n- Suplai lemak subkutan tidak memadai\n- Proses penuaan\n- Berat badan ekstrem\n- Efek agen farmakologis (mis: sedasi)', NULL, NULL, NULL, NULL, '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL),
	('51d23b6d-07e3-11f1-8f82-0200ca9b8436', 'D.0149', 'Termoregulasi Tidak Efektif', '- Stimulasi pusat termoregulasi hipotalamus\n- Fluktuasi suhu lingkungan\n- Proses penyakit (mis: infeksi)\n- Proses penuaan\n- Dehidrasi\n- Ketidaksesuaian pakaian untuk suhu lingkungan\n- Peningkatan kebutuhan oksigen\n- Perubahan laju metabolisme\n- Suhu lingkungan ekstrem\n- Ketidakadekuatan suplai lemak subkutan\n- Berat badan ekstrem\n- Efek agen farmakologis (mis: sedasi)', '(tidak tersedia)', '- Kulit dingin/ hangat\n- Menggigil\n- Suhu tubuh fluktuatif', '(tidak tersedia)', '- Piloereksi\n- Pengisian kapiler >3 detik\n- Tekanan darah meningkat\n- Pucat\n- Frekuensi napas meningkat\n- Takikardia\n- Kejang\n- Kulit kemerahan\n- Dasar kuku sianotik', '2026-02-12 07:20:33', '2026-02-12 07:20:33', NULL);
INSERT INTO `list_siki` (`id`, `intervensi`, `observasi_intervensi`, `terapeutik_intervensi`, `edukasi_intervensi`, `kolaborasi_intervensi`, `created_at`, `updated_at`, `deleted_at`) VALUES
	('80ff74d7-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Jalan Napas', '- Monitor pola napas\n- Monitor bunyi napas tambahan\n- Monitor sputum', '- Pertahankan kepatenan jalan napas\n- Posisikan semifowler atau fowler\n- Lakukan fisioterapi dada, jika perlu\n- Keluarga sumbatan benda padat dengan forsep McGill\n- Berikan oksigen, jika perlu', '- Anjurkan asupan cairan 2000 ml / per hari\n- Ajarkan teknik batuk efektif', '- Kolaborasi pemberian bronkodilator, ekspetoran, mukolitik, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff7709-07e7-11f1-8f82-0200ca9b8436', 'Pemantauan Respirasi', '- Monitor frekuensi, irama, kedalaman dan upaya napas\n- Monitor pola napas\n- Monitor kemampuan batuk efektif\n- Monitor adanya produksi sputum\n- Monitor adanya sumbatan jalan napas\n- Palpasi kesimetrisan ekspansi paru\n- Auskultasi bunyi napas\n- Monitor saturasi oksigen', '- Atur interval pemantauan respirasi sesuai kondisi pasien\n- Dokumentasi hasil pemantauan', '- Jelaskan tujuan dan prosedur pemantauan\n- Informasikan hasil pemantauan, jika perlu', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff787c-07e7-11f1-8f82-0200ca9b8436', 'Terapi Oksigen', '- Monitor kecepatan aliran oksigen\n- Monitor posisi alat terapi oksigen\n- Monitor aliran oksigen secara periodik dan pastikan fraksi yang diberikan cukup\n- Monitor efektifitas terapi oksigen (mis. oksimetri), jika perlu\n- Monitor tanda-tanda hipoventilasi\n- Monitor tanda dan gejala toksikasi oksigen dan atelectasis\n- Monitor tingkat kecemasan akibat terapi oksigen\n- Monitor integritas mukosa hidung akibat pemasangan oksigen', '- Bersihkan sekret pada mulut, hidung dan trakea, jika perlu\n- Pertahan kepatenan jalan napas\n- Siapkan dan atur peralatan pemberian oksigen\n- Berikan oksigen tambahan, jika perlu\n- Tetap berikan saat pasien ditransportasi', '- Ajarkan pasien dan keluarga cara menggunakan oksigen di rumah', '- Kolaborasi penentuan dosis oksigen\n- Kolaborasi penggunaan oksigen saat aktivitas dan/atau tidur', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff78f4-07e7-11f1-8f82-0200ca9b8436', 'Dukungan Ventilasi', '- Identifikasi adanya kelelahan otot bantu napas\n- Identifikasi efek perubahan posisi terhadap status pernapasan\n- Monitor status respirasi dan oksigenasi', '- Pertahankan kepatenan jalan napas\n- Berikan posisi semifowler atau fowler\n- Fasilitasi mengubah posisi senyaman mungkin\n- Berikan oksigenasi sesuai kebutuhan\n- Gunakan bag-valve mask, jika perlu', '- Ajarkan melakukan teknik relaksasi napas dalam\n- Ajarkan mengubah posisi secara mandiri\n- Ajarkan teknik batuk efektif', '- Kolaborasi pemberian bronkodilator, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff7969-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Defribilasi', '- Periksa irama pada monitor setelah RJP 2 menit', '- Lakukan resusitasi jantung paru (RJP) hingga mesin defribilator siap\n- Siapkan dan hidupkan mesin defribilator\n- Pasang monitor EKG\n- Tempelkan paddle sternum (kanan) pada sisi kanan sternum di bawah klavikula dan paddle apeks (kiri) pada garis midaksilaris setinggi elektroda V6\n- Hentikan RJP saat defribilator siap\n- Teriak bahwa defribilator telah siap\n- Berikan syok dengan menekan tombol pada kedua paddle bersamaan\n- Angkat paddle dan langsung lanjutkan RJP tanpa menunggu hasil irama yang muncul pada monitor setelah pemberian defribilasi\n- Lanjutkan RJP sampai 2 menit', NULL, NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff79e6-07e7-11f1-8f82-0200ca9b8436', 'Resusitasi Cairan', '- Monitor status hemodinamik\n- Monitor status oksigen\n- Monitor kelebihan cairan\n- Monitor tanda dan gejala edema paru', '- Pasang jalur IV berukuran besar\n- Berikan infus cairan kristaloid 1 â€“ 2 L pada dewasa\n- Berikan infus cairan kristaloid 20 ml/kgBB pada anak', NULL, '- Kolaborasi penentuan jenis dan jumlah cairan (mis. kristaloid, koloid)', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff7a54-07e7-11f1-8f82-0200ca9b8436', 'Resusitasi Jantung Paru', '- Identifikasi keamanan penolong, lingkungan, dan pasien\n- Identifikasi respon pasien\n- Monitor nadi karotis dan napas setiap 2 menit atau 5 siklus RJP', '- Pakai alat pelindung diri\n- Aktifkan Emergency Medical System\n- Posisikan pasien telentang di tempat datar dan keras\n- Atur posisi penolong berlutut di samping korban\n- Raba nadi karotis dalam waktu <10 detik\n- Berikan rescue breathing jika ditemukan ada nadi tetapi tidak ada napas\n- Kompresi dada 30 kali dikombinasikan dengan bantuan napas (ventilasi) 2 kali jika ditemukan tidak ada nadi dan tidak ada napas\n- Kompresi dengan tumit telapak tangan menumpuk di atas telapak tangan yang lain tegak lurus pada pertengahan dada (seperdua bawah sternum)\n- Kompresi dengan kedalaman kompresi 5 â€“ 6 cm dengan kecepatan 100 â€“ 120 kali / menit\n- Bersihkan dan buka jalan napas dengan head tilt â€“ chin lift atau jaw thrust (jika curiga cedera servikal)\n- Berikan bantuan napas dengan menggunakan Bag Valve Mask dengan Teknik EC-Clamp\n- Kombinasikan kompresi dan ventilasi selama 2 menit atau sebanyak 5 siklus\n- Hentikan RJP jika ditemukan adanya tanda-tanda kehidupan, ditemukan adanya tanda-tanda kematian biologis, Do Not Resuscitation (DNR)', '- Jelaskan tujuan dan prosedur Tindakan kepada keluarga atau pengantar pasien', '- Kolaborasi tim medis untuk bantuan hidup lanjut', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff7ade-07e7-11f1-8f82-0200ca9b8436', 'Perawatan Jantung Akut', '- Identifikasi karakteristik nyeri dada (meliputi factor pemicu dan Pereda, kualitas Lokasi, radiasi, skala, durasi dan frekuensi)\n- Monitor EKG 12 sadapan untuk perubahan ST dan T\n- Monitor aritmia (kelainan irama dan frekuensi)\n- Monitor elektrolit yang dapat meningkatkan risiko aritmia\n- Monitor saturasi oksigen\n- Identifikasi stratifikasi pada sindrom koroner akut', '- Pasang akses intravena\n- Puasakan hingga bebas nyeri\n- Berikan terapi relaksasi untuk mengurangi ansietas dan stress\n- Sediakan lingkungan yang kondusif untuk beristirahat dan pemulihan\n- Siapkan menjalani intervensi koroner perkutan, jika perlu\n- Berikan dukungan emosional', '- Anjurkan segera melaporkan nyeri dada\n- Anjurkan menghindari manuver valsava\n- Jelaskan Tindakan yang dijalani pasien\n- Ajarkan teknik menurunkan kecemasan dan ketakutan', '- Kolaborasi pemberian antiplatelet, jika perlu\n- Kolaborasi pemberian antianginal, jika perlu\n- Kolaborasi pemberian morfin, jika perlu\n- Kolaborasi pemberian inotropic, jika perlu\n- Kolaborasi pemberian obat untuk mencegah manuver valvasa\n- Kolaborasi pencegahan trombus dengan antikoagulan, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff7b5c-07e7-11f1-8f82-0200ca9b8436', 'Perawatan Sirkulasi', '- Periksa sirkulasi perifer (mis. nadi perifer, edema, pengisian kapiler, warna, suhu, ankle-brachial index)\n- Identifikasi faktor risiko gangguan sirkulasi (mi. diabetes, perokok, orang tua, hipertensi dan kadar kolesterol tinggi)\n- Monitor panas, kemerahan, nyeri, atau bengkak pada ekstermitas', '- Hindari pemasangan infus atau pengambilan darah di area keterbatasan perfusi\n- Hindari pengukuran tekanan darah pada ekstermitas dengan keterbatasan perfusi\n- Lakukan pencegahan infeksi\n- Lakukan perawatan kaki dan kuku\n- Lakukan hidrasi', '- Anjurkan berhenti merokok\n- Anjurkan berolahraga rutin\n- Anjurkan mengecek air mandi untuk menghindari kulit terbakar\n- Anjurkan menggunakan obat penurn tekanan darah, antikoagulan, dan penurun kolesterol, jika perlu\n- Anjurkan minum obat pengontrol tekanan darah secara teratur\n- Anjurkan menghindari penggunaan obat penyekat beta\n- Anjurkan melakukan perawatan kulit yang tepat\n- Anjurkan program rehabilitasi vascular\n- Anjurkan program diet untuk memperbaiki sirkulasi\n- Informasikan tanda dan gejala darurat yang harus dilaporkan ( mis. rasa sakit yang tidak hilang saat istirahat, luka tidak sembuh, hilangnya rasa)', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff7c72-07e7-11f1-8f82-0200ca9b8436', 'Pencegahan Perdarahan', '- Monitor tand dan gejala perdarahan\n- Monitor tanda-tanda vital ortostatik', '- Pertahankan bed rest selama perdarahan\n- Batasi tindakan invasif, jika perlu', 'Edukasi\n- Jelaskan tanda dan gejala perdarahan\n- Anjurkan untuk menghindari aspirin atau antikoagulan\n- Anjurkan untuk meningkatkan asupan makanan dan vitamin K', '- Kolaborasi pemberian obat pengontrol perdarahan, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff7cf6-07e7-11f1-8f82-0200ca9b8436', 'Balut Tekan', '- Periksa kecepatan dan kekuatan denyut nadi distal\n- Periksa akral, kondisi kulit dan pengisian kapiler distal', '- Pasang sarung tangan\n- Tinggikan bagian tubuh yang cedera di atas level jantung, jika tidak ada fraktur\n- Tekan kasa dengan kuat di atas luka\n- Fiksasi kasa dengan plester setelah perdarahan berhenti\n- Tekan arteri (pressure point) yang mengarah ke area perdarahan', '- Jelaskan tujuan dan prosedur balut tekan\n- Anjurkan membatasi gerak pada area cedera', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff7d77-07e7-11f1-8f82-0200ca9b8436', 'Pencegahan Syok', '- Monitor status kardiopulmonal\n- Monitor status oksigenasi\n- Monitor status cairan\n- Monitor tingkat kesadaran dan respon pupil\n- Periksa riwayat alergi', '- Berikan oksigen untuk mempertahankan saturasi oksigen >94%\n- Persiapkan intubasi dan ventilasi mekanis, jika perlu\n- Pasang jalur IV, jika perlu\n- Pasang kateter urine untuk menilai produksi urine, jika perlu\n- Lakukan skin test untuk mencegah reaksi alergi', '- Jelaskan penyebab/ faktor risiko syok\n- Jelaskan tanda dan gejala awal syok\n- Anjurkan memperbanyak asupan cairan oral\n- Anjurkan menghindari alergen', '- Kolaborasi pemberian IV, jika perlu\n- Kolaborasi pemberian antiinflamasi, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff7dff-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Nutrisi', '- Identifikasi status nutrisi\n- Identifikasi alergi dan intoleransi makanan\n- Identifikasi kebutuhan kalori dan nutrien\n- Monitor asupan makanan\n- Monitor berat badan', NULL, '- Anjurkan posisi duduk\n- Ajarkan diet yang diprogramkan', '- Kolaborasi pemberian medikasi sebelum makan, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff7e9f-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Diare', '- Identifikasi penyebab diare\n- Identifikasi riwayat pemberian makanan\n- Monitor warna, volume, frekuensi, dan konsistensi tinja\n- Monitor tanda dan gejala hypovolemia\n- Monitor jumlah pengeluaran diare', '- Berikan asupan cairan oral\n- Pasang jalur intravena\n- Berikan cairan intravena', '- Anjurkan makanan porsi kecil dan sering secara bertahap\n- Anjurkan mengindari makanan pembentuk gas, pedas dan mengandung laktosa', '- Kolaborasi pemberian obat antimotilitas (mis. loperamide)\n- Kolaborasi pemberian obat antispasmodic/ spasmolitik (mis. scopma)\n- Kolaborasi pemberian obat pengeras feses (mis. attalpugit)', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff8029-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Hipovolemia', '- Periksa tanda dan gejala hipovolemia\n- Monitor intake dan output cairan', '- Hitung kebutuhan cairan\n- Berikan posisi modified Trendelenburg\n- Berikan asupan cairan oral', '- Anjurkan memperbanyak asupan cairan oral\n- Anjurkan mengindari perubahan posisi mendadak', '- Kolaborasi pemberian cairan IV isotonis (mis. NaCl, RL)\n- Kolaborasi pemberian cairan IV hipotonis', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff8090-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Hipoglikemia', '- Identifikasi tanda dan gejala hipoglikemia\n- Idnetifikasi kemungkinan penyebab hipoglikemia', '- Berikan karbohidrat sederhana, jika perlu\n- Berikan glukagon, jika perlu\n- Pertahankan kepatenan jalan napas\n- Pertahankan akses IV, jika perlu', '- Anjurkan membawa karbohidrat sederhana setiap saat\n- Anjurkan monitor kadar glukosa darah\n- Ajarkan pengelolaan hipoglikemia\n- Ajarkan perawatan mandiri untuk mencegah hipoglikemia', '- Kolaborasi pemberian dekstrose, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff8104-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Hiperglikemia', '- Identifikasi kemungkinan penyebab hiperglikemia\n- Identifikasi situasi yang menyebabkan kebutuhan insulin mneingkat\n- Monitor kadar glukosa darah, jika perlu\n- Monitor tanda dan gejala hiperglikemia\n- Monitor intake dan output cairan', '- Berikan asupan cairan oral', '- Anjurkan monitor kadar glukosa darah secara mandiri\n- Anjurkan kepatuhan terhadap diet dan olahraga\n- Ajarkan pengelolaan diabetes', '- Kolaborasi pemberian insulin, jika perlu\n- Kolaborasi pemberian cairan IV, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff8168-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Cairan', '- Monitor status hidrasi', '- Berikan asupan cairan, sesuai kebutuhan\n- Berikan cairan intravena, jika perlu', NULL, '- Kolaborasi pemberian diuretik, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff81c2-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Elektrolit', '- Identifikasi tanda dan gejala ketidakseimbangan kadar elektrolit\n- Identifikasi penyebab ketidakseimbangan elektrolit\n- Identifikasi kehilangan alektrolit melalui cairan', '- Berikan cairan, jika perlu\n- Pasang akses intravena, jika perlu', '- Jelaskan jenis, penyebab, dan penanganan ketidakseimbangan elektrolit', '- Kolaborasi pemberian suplemen elektrolit, sesuai indikasi', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff8218-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Eliminasi Urine', '- Identifikasi tanda dan gejala retensi atau inkotinensia urine\n- Identifikasi faktor yang menyebabkan retensi atau inkontinensia urine\n- Monitor eliminasi urine', '- Batasi asupan cairan, jika perlu', '- Ajarkan tanda dan gejala infeksi saluran kemih\n- Anjurkan minum yang cukup, jika tidak ada kontraindikasi\n- Anjurkan mengurangi minum menjelang tidur', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff8383-07e7-11f1-8f82-0200ca9b8436', 'Kateterisasi Urine', '- Periksa kondisi pasien (mis: kesadaran, tanda-tanda vital, daerah perineal, distensi kandung kemih, inkontinensia urin, refleks berkemih)', '- Siapkan peralatan, bahan-bahan, dan ruangan Tindakan\n- Siapkan pasien: bebaskan pakaian bawah dan posisikan dorsal rekumben (untuk Wanita) dan supine (untuk laki-laki)\n- Pasang sarung tangan\n- Bersihkan daerah perineal atau preposium dengan cairan NaCl atau aquades\n- Lakukan insersi kateter urin dengan menerapkan prinsip aseptic\n- Sambungkan kateter urin dengan urin bag\n- Isi balon dengan NaCl 0,9% sesuai anjuran pabrik\n- Fiksasi selang kateter diatas simpisis atau di paha\n- Pastikan urin bag ditempatkan lebih rendah dari kandung kemih\n- Berikan label waktu pemasangan', '- Jelaskan tujuan dan prosedur pemasangan kateter urin\n- Anjurkan menarik napas saat insersi selang kateter', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff83fe-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Konstipasi', '- Periksa tanda dan gejala konstipasi\n- Periksa pergerakan usus, karakteristik feses (konsistensi, bentuk, volume,  dan warna)\n- Identifikasi faktor risiko konstipasi (mis: obat-obatan, tirah baring, dan diet rendah serat\n- Monitor tanda dan gejala rupture usus dan/atau peritonitis', '- Anjurkan diet tinggi serat\n- Lakukan masase abdomen, jika perlu\n- Lakukan evaluasi feses secara manual, jika perlu\n- Berikan enema atau irigasi, jika perlu', '- Jelaskan etiologi masalah dan alasan Tindakan\n- Anjurkan peningkatan asupan cairan, jika tidak ada kontraindikasi\n- Latih buang air besar secara teratur\n- Ajarkan cara mengatasi konstipasi/impaksi', '- Konsultasi dengan tim medis tentang penurunan/peningkatan frekuensi suara usus\n- Kolaborasi penggunaan obat pencahar, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ff84a3-07e7-11f1-8f82-0200ca9b8436', 'Dukungan Ambulansi', '- Identifikasi adanya nyeri atau keluhan fisik lainnya\n- Identifikasi toleransi fisik melakukan ambulasi\n- Monitor frekuensi jantung dan tekanan darah sebelum memulai ambulasi\n- Monitor kondisi umum selama melakukan ambulasi', '- Fasilitasi aktivitas ambulasi dengan alat bantu (mis: tongkat, kruk)\n- Fasilitasi melakukan mobilisasi fisik, jika perlu\n- Libatkan keluarga untuk membantu pasien dalam meningkatkan ambulasi', '- Jelaskan tujuan dan prosedur ambulasi\n- Anjurkan melakukan ambulasi dini\n- Ajarkan ambulasi sederhana yang harus dilakukan (mis: berjalan dari tempat tidur ke kursi roda, berjalan dari tempat tidur ke kamar mandi, berjalan sesuai toleransi)', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ffd0a6-07e7-11f1-8f82-0200ca9b8436', 'Dukungan Mobilisasi', '- Identifikasi adanya nyeri atau keluhan fisik lainnya\n- Identifikasi toleransi fisik melakukan pergerakan\n- Monitor frekuensi jantung dan tekanan darah sebelum memulai mobilisasi\n- Monitor kondisi umum selama melakukan mobilisasi', '- Fasilitasi aktivitas mobilisasi dengan alat bantu (mis: pagar tempat tidur)\n- Fasilitasi melakukan pergerakan, jika perlu\n- Libatkan keluarga untuk membantu pasien dalam meningkatkan pergerakan', '- Jelaskan tujuan dan prosedur mobilisasi\n- Anjurkan melakukan mobilisasi dini\n- Ajarkan mobilisasi sederhana yang harus dilakukan (mis: duduk di tempat tidur, duduk di sisi tempat tidur, pindah dari tempat tidur ke kursi)', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ffd16a-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Energi', '- Identifikasi gangguan fungsi tubuh yang mengakibatkan kelelahan\n- Monitor kelelahan fisik dan emosional\n- Monitor pola dan jam tidur\n- Monitor lokasi dan ketidaknyamanan selama melakukan aktivitas', '- Sediakan lingkungan nyaman dan rendah stimulus (mis: cahaya, suara, kunjungan)\n- Lakukan latihan rentang gerak pasif dan/atau aktif\n- Berikan aktivitas distraksi yang menenangkan\n- Fasilitasi duduk di sisi tempat tidur, jika tidak dapat berpindah atau berjalan', '- Anjurkan tirah baring\n- Anjurkan melakukan aktivitas secara bertahap\n- Anjurkan menghubungi perawat jika tanda dan gejala kelelahan tidak berkurang\n- Ajarkan strategi koping untuk mengurangi kelelahan', '- Kolaborasi dengan ahli gizi tentang cara meningkatkan asupan makanan', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ffd1f9-07e7-11f1-8f82-0200ca9b8436', 'Orientasi Realita', '- Monitor perubahan orientasi\n- Monitor perubahan kognitif dan perilaku', '- Perkenalkan nama saat memulai interaksi\n- Orientasikan orang, tempat, dan waktu\n- Hadirkan realita (mis: beri penjelasan alternatif, hindari perdebatan)\n- Sediakan lingkungan dan rutinitas secara konsisten\n- Atur stimulus sensorik dan lingkungan (mis: kunjungan, pemandangan, suara, pencahayaan, bau, dan sentuhan)\n- Gunakan simbol dalam mengorientasikan lingkungan (mis: tanda, gambar, warna)\n- Libatkan dalam terapi kelompok orientasi\n- Berikan waktu istirahat dan tidur yang cukup, sesuai kebutuhan\n- Fasilitasi akses informasi (mis: televisi, surat kabad, radio), jika perlu', '- Anjurkan perawatan diri secara mandiri\n- Anjurkan penggunaan alat bantu (mis: kacamata, alat bantu dengar, gigi palsu)\n- Ajarkan keluarga dalam perawatan orientasi lansia', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ffd278-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Delirium', '- Identifikasi faktor risiko delirium (mis: usia >75 tahun, disfungsi kognitif, gangguan penglihatan/pendengaran, penurunan kemampuan fungsional, infeksi, hipo/hipertemia, hipoksia, malnutrisi, efek obat, toksin, gangguan tidur, stres)\n- Identifikasi tipe delirium (mis: hipoaktif, hiperaktif, campuran)\n- Monitor status neurologis dan tingkat delirium', '- Berikan pencahayaan yang baik\n- Sediakan jam dan kalender yang mudah dibaca\n- Hindari stimulus sensorik berlebihan (mis: televisi, pengumuman interkom)\n- Lakukan pengekangan fisik, sesuai indikasi\n- Sediakan informasi tentang apa yang terjadi dan apa yang dapat terjadi selanjutnya\n- Batasi pembuatan keputusan\n- Hindari memvalidasi mispersepsi atau interpretasi realita yang tidak akurat (mis: halusinasi, waham)\n- Nyatakan persepsi dengan cara yang tenang, meyakinkan, dan tidak argumentative\n- Fokus pada apa yang dikenali dan bermakna saat interaksi interpersonal\n- Lakukan reorientasi\n- Sediakan lingkungan fisik dan rutinitas harian yang konsisten\n- Gunakan isyarat lingkungan untuk stimulasi memori, reorientasi, dan meningkatkan perilaku yang sesuai (mis: tanda, gambar, jam, kalender, dan kode warna pada lingkungan)\n- Berikan informasi baru secara perlahan, sedikit demi sedikit, diulang-ulang', '- Anjurkan kunjungan keluarga, jika perlu\n- Anjurkan penggunaan alat bantu sensorik (mis: kacamata, alat bantu dengar, dan gigi palsu)', '- Kolaborasi pemberian obat ansietas atau agitasi, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ffd303-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Demensia', '- Identifikasi Riwayat fisik, sosial, psikologis, dan kebiasaan\n- Identifikasi pola aktivitas (mis: tidur, minum obat, eliminasi, asupan oral, perawatan diri)', '- Sediakan lingkungan aman, nyaman, konsisten, dan rendah stimulus (mis: music tenang, dekorasi sederhana, pencahayaan memadai, makan Bersama pasien lain)\n- Orientasikan waktu, tempat, dan orang\n- Gunakan distraksi untuk mengatasi masalah perilaku\n- Libatkan keluarga dalam merencanakan, menyediakan, dan mengevaluasi perawatan\n- Fasilitasi orientasi dengan simbol-simbol (mis: dekorasi, papan petunjuk, foto diberi nama, huruf besar)\n- Libatkan kegiatan individua tau kelompok sesuai kemampuan kognitif dan minat', '- Anjurkan memperbanyak istirahat\n- Ajarkan keluarga cara perawatan demensia', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ffd478-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Nyeri', '- Identifikasi lokasi, karakteristik, durasi, frekuensi, kualitas, intensitas nyeri\n- Identifikasi skala nyeri\n- Idenfitikasi respon nyeri non verbal\n- Identifikasi faktor yang memperberat dan memperingan nyeri\n- Identifikasi pengetahuan dan keyakinan tentang nyeri\n- Identifikasi pengaruh budaya terhadap respon nyeri\n- Identifikasi pengaruh nyeri pada kualitas hidup\n- Monitor keberhasilan terapi komplementer yang sudah diberikan\n- Monitor efek samping penggunaan analgetik', '- Berikan teknik nonfarmakologis untuk mengurangi nyeri \n- Kontrol lingkungan yang memperberat rasa nyeri\n- Fasilitasi istirahat dan tidur\n- Pertimbangkan jenis dan sumber nyeri dalam pemilihan strategi meredakan nyeri', '- Jelaskan penyebab, periode, dan pemicu nyeri\n- Jelaskan strategi meredakan nyeri\n- Anjurkan memonitor nyeri secara mandiri\n- Anjurkan menggunakan analgesik secara tepat\n- Ajarkan teknik farmakologis untuk mengurangi nyeri', '- Kolaborasi pemberian analgetik, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ffd551-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Mual', '- Identifikasi pengalaman mual\n- Identifikasi isyarat nonverbal ketidaknyamanan (mis: bayi, anak-anak, dan mereka yang tidak dapat berkomunikasi secara efektif)\n- Identifikasi dampak mual terhadap kualitas hidup (mis: nafsu makan, aktivitas, kinerja, tanggung jawab peran, dan tidur)\n- Identifikasi faktor penyebab mual (mis: pengobatan dan prosedur)\n- Identifikasi antiemetik untuk mencegah mual (kecuali mual pada kehamilan)\n- Monitor mual (mis: frekuensi, durasi, dan tingkat keparahan)', '- Kendalikan faktor lingkungan penyebab mual (mis: bau tidak sedap, suara, dan rangsangan visual yang tidak menyenangkan)\n- Kurangi atau hilangkan keadaan penyebab mual (mis: kecemasan, ketakutan, kelelahan)\n- Berikan makanan dalam jumlah kecil dan menarik\n- Berikan makanan dingin, cairan bening, tidak berbau, dan tidak berwarna, jika perlu', '- Anjurkan istirahat dan tidur yang cukup\n- Anjurkan sering membersihkan mulut, kecuali jika merangsang mual\n- Anjurkan makanan tinggi karbohidrat, dan rendah lemak\n- Ajarkan penggunaan teknik non farmakologis untuk mengatasi mual', '- Kolaborasi pemberian obat antiemetik, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('80ffd612-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Muntah', '- Identifikasi pengalaman muntah\n- Identifikasi isyarat nonverbal ketidaknyamanan (mis: bayi, anak-anak, dan mereka yang tidak dapat berkomunikasi secara efektif)\n- Identifikasi dampak muntah terhadap kualitas hidup (mis: nafsu makan, aktivitas, kinerja, tanggung jawab peran, dan tidur)\n- Identifikasi faktor penyebab muntah (mis: pengobatan dan prosedur)\n- Identifikasi antiemetik untuk mencegah muntah (kecuali muntah pada kehamilan)\n- Monitor muntah (mis: frekuensi, durasi, dan tingkat keparahan)', '- Kontrol lingkungan penyebab muntah (mis: bau tidak sedap, suara, dan stimulasi visual yang tidak menyenangkan)\n- Kurangi atau hilangkan keadaan penyebab muntah (mis: kecemasan, ketakutan)\n- Atur posisi untuk mencegah aspirasi\n- Pertahankan kepatenan jalan napas\n- Bersihkan mulut dan hidung\n- Berikan dukungan fisik saat muntah (mis: membantu membungkuk atau menundukkan kepala)\n- Berikan kenyamanan selama muntah (mis: kompres dingin di dahi, atau sediakan pakaian kering dan bersih)\n- Berikan cairan yang tidak mengandung karbonasi minimal 30 menit setelah muntah', '- Anjurkan membawa kantong plastik untuk menampung muntah\n- Anjurkan memperbanyak istirahat\n- Ajarkan penggunaan Teknik non farmakologis untuk mengelola muntah (mis: biofeedback, hipnosis, relaksasi, terapi musik, akupresur)', '- Kolaborasi pemberian obat antiemetik, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('81002678-07e7-11f1-8f82-0200ca9b8436', 'Reduksi Ansietas', '- Identifikasi saat tingkat ansietas berubah (mis: kondisi, waktu, stresor)\n- Identifikasi kemampuan mengambil keputusan\n- Monitor tanda-tanda ansietas (verbal dan nonverbal)', '- Ciptakan suasana terapeutik untuk menumbuhkan kepercayaan\n- Temani pasien untuk mengurangi kecemasan, jika memungkinkan\n- Pahami situasi yang membuat ansietas\n- Dengarkan dengan penuh perhatian\n- Gunakan pendekatan yang tenang dan meyakinkan\n- Tempatkan barang pribadi yang memberikan kenyamanan\n- Motivasi mengidentifikasi situasi yang memicu kecemasan\n- Diskusikan perencanaan realistis tentang peristiwa yang akan datang', '- Jelaskan prosedur, termasuk sensasi yang mungkin dialami\n- Informasikan secara faktual mengenai diagnosis, pengobatan, dan prognosis\n- Anjurkan keluarga untuk tetap Bersama pasien, jika perlu\n- Anjurkan melakukan kegiatan yang tidak kompetitif, sesuai kebutuhan\n- Anjurkan mengungkapkan perasaan dan persepsi\n- Latih kegiatan pengalihan untuk mengurangi ketegangan\n- Latih penggunaan mekanisme pertahanan diri yang tepat\n- Latih teknik relaksasi', '- Kolaborasi pemberian obat antiansietas, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('810027dd-07e7-11f1-8f82-0200ca9b8436', 'Dukungan Pengambilan Keputusan', '- Identifikasi persepsi mengenai masalah dan informasi yang memicu konflik', '- Fasilitasi mengklarifikasi nilai dan harapan yang membantu membuat pilihan\n- Diskusikan kelebihan dan kekurangan dari setiap solusi\n- Fasilitasi melihat situasi secara realistic\n- Motivasi mengungkapkan tujuan perawatan yang diharapkan\n- Fasilitasi pengambilan keputusan secara kolaboratif\n- Hormati hak pasien untuk menerima atau menolak informasi\n- Fasilitasi menjelaskan keputusan kepada orang lain, jika perlu\n- Fasilitasi hubungan antara pasien, keluarga, dan tenaga Kesehatan lainnya', '- Jelaskan alternatif solusi secara jelas\n- Berikan informasi yang diminta pasien', '- Kolaborasi dengan tenaga Kesehatan lain dalam memfasilitasi pengambilan keputusan', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('810028d7-07e7-11f1-8f82-0200ca9b8436', 'Promosi Koping', '- Identifikasi kegiatan jangka pendek dan Panjang sesuai tujuan\n- Identifikasi kemampuan yang dimiliki\n- Identifikasi  sumber daya yang tersedia untuk memenuhi tujuan\n- Identifikasi pemahaman proses penyakit\n- Identifikasi dampak situasi terhadap peran dan hubungan\n- Identifikasi metode penyelesaian masalah\n- Identifikasi kebutuhan dan keinginan terhadap dukungan sosial', '- Diskusikan perubahan peran yang dialami\n- Gunakan pendekatan yang tenang dan meyakinkan\n- Diskusikan alasan mengkritik diri sendiri\n- Diskusikan untuk mengklarifikasi kesalahpahaman dan mengevaluasi perilaku sendiri\n- Diskusikan konsekuensi tidak menggunakan rasa bersalah dan rasa malu\n- Diskusikan risiko yang menimbulkan bahaya pada diri sendiri\n- Fasilitasi dalam memperoleh informasi yang dibutuhkan\n- Berikan pilihan realistis mengenai aspek-aspek tertentu dalam perawatan\n- Motivasi untuk menentukan harapan yang realistis\n- Tinjau Kembali kemampuan dalam pengambilan keputusan\n- Hindari mengambil keputusan saat pasien berada dibawah tekanan\n- Motivasi terlibat dalam kegiatan sosial\n- Motivasi mengidentifikasi sistem pendukung yang tersedia\n- Damping saat berduka (mis: penyakit kronis, kecacatan)\n- Perkenalkan dengan orang atau kelompok yang berhasil mengalami pengalaman sama\n- Dukung penggunaan mekanisme pertahanan yang tepat\n- Kurangi rangsangan lingkungan yang mengancam', '- Anjurkan menjalin hubungan yang memiliki kepentingan dan tujuan sama\n- Anjurkan penggunaan sumber spiritual, jika perlu\n- Anjurkan mengungkapkan perasaan dan persepsi\n- Anjurkan keluarga terlibat\n- Anjurkan membuat tujuan yang lebih spesifik\n- Ajarkan cara memecahkan masalah secara konstruktif\n- Latih penggunaan Teknik relaksasi\n- Latih keterampilan sosial, sesuai kebutuhan\n- Latih mengembangkan penilaian obyektif', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('810029b9-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Waham', '- Monitor waham yang isinya membahayakan diri sendiri, orang lain, dan lingkungan\n- Monitor efek terapeutik dan efek samping obat', '- Bina hubungan interpersonal saling percaya\n- Tunjukkan sikap tidak menghakimi secara konsisten\n- Diskusikan waham dengan berfokus pada perasaan yang mendasari waham \n- Hindari perdebatan tentang keyakinan yang keliru, nyatakan keraguan sesuai fakta\n- Hindari memperkuat gagasan waham\n- Sediakan lingkungan aman dan nyaman\n- Berikan aktivitas rekreasi dan pengalihan sesuai kebutuhan\n- Lakukan intervensi pengontrolan perilaku waham (Mis: limit setting, pembatasan wilayah, pengekangan fisik, atau seklusi)', '- Anjurkan mengungkapkan dan memvalidasi waham (uji realitas) dengan orang yang dipercaya (pemberi asuhan/keluarga)\n- Anjurkan melakukan rutinitas harian secara konsisten\n- Latih manajemen stres\n- Jelaskan tentang waham serta penyakit terkait (mis: delirium, skizofrenia, atau depresi), cara mengatasi dan obat yang diberikan', '- Kolaborasi pemberian obat, sesuai indikasi', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('81002a81-07e7-11f1-8f82-0200ca9b8436', 'Edukasi Kesehatan', '- Identifikasi kesiapan dan kemampuan menerima informasi\n- Identifikasi faktor-faktor yang dapat meningkatkan dan menurunkan motivasi perilaku hidup bersih dan sehat', '- Sediakan materi dan media Pendidikan Kesehatan\n- Jadwalkan Pendidikan Kesehatan sesuai kesepakatan\n- Berikan kesempatan untuk bertanya', '- Jelaskan faktor risiko yang dapat mempengaruhi Kesehatan\n- Ajarkan perilaku hidup bersih dan sehat\n- Ajarkan strategi yang dapat digunakan untuk meningkatkan perilaku hidup bersih dan sehat', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('81002b2c-07e7-11f1-8f82-0200ca9b8436', 'Dukungan Emosional', '- Identifikasi fungsi marah, frustrasi, dan amuk bagi pasien\n- Identifikasi hal yang telah memicu emosi', '- Fasilitasi mengungkapkan perasaan cemas, marah, atau sedih\n- Buat pernyataan suportif atau empati selama fase berduka\n- Lakukan sentuhan untuk memberikan dukungan (mis: merangkul, menepuk-nepuk)\n- Tetap Bersama pasien dan pastikan keamanan selama ansietas, jika perlu\n- Kurangi tuntutan berpikir saat sakit atau lelah', '- Jelaskan konsekuensi tidak menghadapi rasa bersalah dan malu\n- Anjurkan mengungkapkan perasaan yang dialami (mis: ansietas, marah, sedih)\n- Anjurkan mengungkapkan pengalaman emosional sebelumnya dan pola respons yang biasa digunakan\n- Ajarkan penggunaan mekanisme pertahanan yang tepat', '- Rujuk untuk konseling, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('81002be1-07e7-11f1-8f82-0200ca9b8436', 'Promosi Dukungan Keluarga', '- Identifikasi sumber daya fisik, emosional, dan pendidikan keluarga\n- Identifikasi kebutuhan dan harapan anggota keluarga\n- Identifikasi persepsi tentang situasi, pemicu kejadian, perasaan dan perilaku pasien\n- Identifikasi stresor situasional anggota keluarga lainnya\n- Diskusikan anggota keluarga yang akan dilibatkan dalam perawatan\n- Diskusikan kemampuan dan perencanaan keluarga dalam perawatan\n- Dukung anggota keluarga untuk menjaga dan mempertahankan hubungan keluarga\n- Hargai keputusan yang dibutuhkan keluarga\n- Hargai mekanisme perawatan yang digunakan keluarga', NULL, '- Jelaskan kepada keluarga tentang perawatan dan pengobatan yang dijalani pasien\n- Anjurkan keluarga bersikap asertif\n- Anjurkan meningkatkan aspek positif dari situasi yang dijalani pasien', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('81002c8a-07e7-11f1-8f82-0200ca9b8436', 'Perawatan Luka', '- Monitor karakteristik luka (mis: drainase, warna, ukuran , bau)\n- Monitor tanda-tanda infeksi', '- Lepaskan balutan dan plester secara perlahan\n- Cukur rambut di sekitar daerah luka, jika perlu\n- Bersihkan dengan cairan NaCl atau pembersih nontoksik, sesuai kebutuhan\n- Bersihkan jaringan nekrotik\n- Berikan salep yang sesuai ke kulit/lesi, jika perlu\n- Pasang balutan sesuai jenis luka\n- Pertahankan Teknik steril saat melakukan perawatan luka\n- Ganti balutan sesuai jumlah eksudat dan drainase\n- Jadwalkan perubahan posisi setiap 2 jam atau sesuai kondisi pasien\n- Berikan diet dengan kalori 30 â€“ 35 kkal/kgBB/hari dan protein 1,25 â€“ 1,5 g/kgBB/hari\n- Berikan suplemen vitamin dan mineral (mis: vitamin A, vitamin C, Zinc, asam amino), sesuai indikasi\n- Berikan terapi TENS (stimulasi saraf transcutaneous), jika perlu', '- Jelaskan tanda dan gejala infeksi\n- Anjurkan mengkonsumsi makanan tinggi kalori dan protein\n- Ajarkan prosedur perawatan luka secara mandiri', '- Kolaborasi prosedur debridement (mis: enzimatik, biologis, mekanis, autolitik), jika perlu\n- Kolaborasi pemberian antibiotik, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('81002d20-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Hipertermia', '- Identifikasi penyebab hipertermia (mis: dehidrasi, terpapar lingkungan panas, penggunaan inkubator)\n- Monitor suhu tubuh\n- Monitor kadar elektrolit\n- Monitor haluaran urin\n- Monitor komplikasi akibat hipertermia', '- Sediakan lingkungan yang dingin\n- Longgarkan atau lepaskan pakaian\n- Basahi dan kipasi permukaan tubuh\n- Berikan cairan oral\n- Ganti linen setiap hari atau lebih sering jika mengalami hyperhidrosis (keringat berlebih)\n- Lakukan pendinginan eksternal (mis: selimut hipotermia atau kompres dingin pada dahi, leher, dada, abdomen, aksila)\n- Hindari pemberian antipiretik atau aspirin\n- Berikan oksigen, jika perlu', '- Anjurkan tirah baring', '- Kolaborasi pemberian cairan dan elektrolit intravena, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('81002dd3-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Hipotermia', '- Monitor suhu tubuh\n- Identifikasi penyebab hipotermia (mis: terpapar suhu lingkungan rendah, pakaian tipis, kerusakan hipotalamus, penurunan laju metabolisme, kekurangan lemak subkutan)\n- Monitor tanda dan gejala akibat hipotermia (mis: hipotermia ringan: takipnea, disartria, menggigil, hipertensi, diuresis; hipotermia sedang: aritmia, hipotensi, apatis, koagulopati, refleks menurun; hipotermia berat: oliguria, refleks menghilang, edema paru, asam-basa abnormal)', '- Sediakan lingkungan yang hangat (mis: atur suhu ruangan, inkubator)\n- Ganti pakaian dan/atau linen yang basah\n- Lakukan penghangatan pasif (mis: selimut, menutup kepala, pakaian tebal)\n- Lakukan penghangatan aktif eksternal (mis: kompres hangat, botol hangat, selimut hangat, perawatan metode kangguru)\n- Lakukan penghangatan aktif internal (mis: infus cairan hangat, oksigen hangat, lavase peritoneal dengan cairan hangat)', '- Anjurkan makan/minum hangat', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('81002e74-07e7-11f1-8f82-0200ca9b8436', 'Manajemen Anafilaksis', '- Identifikasi kepatenan jalan napas\n- Identifikasi tanda-tanda vital\n- Identifikasi alergen\n- Monitor tanda-tanda awal syok\n- Monitor kejadian anafilaktik berulang', '- Berikan posisi nyaman\n- Pertahankan kepatenan jalan napas\n- Pasang infus NaCl 0,9% atau ringer laktat, sesuai kebutuhan\n- Berikan oksigen via masker 10-12 L/menit', '- Anjurkan menyiapkan obat-obat alergi di rumah\n- Anjurkan mencegah kejadian anafilaktik', '- Kolaborasi pemberian antihistamin, jika perlu\n- Kolaborasi pemberian kortikosteroid, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('81002f3d-07e7-11f1-8f82-0200ca9b8436', 'Pencegahan Cedera', '- Identifikasi area lingkungan yang berpotensi menyebabkan cedera\n- Identifikasi obat yang berpotensi menyebabkan cedera\n- Identifikasi kesesuaian alas kaki atau stoking elastis pada ekstremitas bawah', '- Sediakan pencahayaan yang memadai\n- Gunakan lampu tidur selama jam tidur\n- Sosialisasikan pasien dan keluarga dengan lingkungan ruang rawat (mis: penggunaan telepon, tempat tidur, penerangan ruangan, dan lokasi kamar mandi)\n- Gunakan alas kaki jika berisiko mengalami cedera serius\n- Sediakan alas kaki antislip\n- Sediakan pispot dan urinal untuk eliminasi di tempat tidur, jika perlu\n- Pastikan bel panggilan atau telepon mudah terjangkau\n- Pastikan barang-barang pribadi mudah dijangkau\n- Pertahankan posisi tempat tidur di posisi terendah saat digunakan\n- Pastikan roda tempat tidur atau kursi roda dalam kondisi terkunci\n- Gunakan pengaman tempat tidur sesuai dengan kebijakan fasilitas pelayanan Kesehatan\n- Pertimbangkan penggunaan alarm elektronik pribadi atau alarm sensor pada tempat tidur atau kursi\n- Diskusikan mengenai latihan dan terapi fisik yang diperlukan\n- Diskusikan mengenai alat bantu mobilitas yang sesuai (mis: tongkat atau alat bantu jalan)\n- Diskusikan Bersama anggota keluarga yang dapat mendampingi pasien\n- Tingkatkan frekuensi observasi dan pengawasan pasien, sesuai kebutuhan', '- Jelaskan alasan intervensi pencegahan jatuh ke pasien dan keluarga\n- Anjurkan berganti posisi secara perlahan dan duduk selama beberapa menit sebelum berdiri', NULL, '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('81002ffc-07e7-11f1-8f82-0200ca9b8436', 'Pencegahan Infeksi', '- Monitor tanda dan gejala infeksi lokal dan sistemik', '- Batasi jumlah pengunjung\n- Berikan perawatan kulit pada area edema\n- Cuci tangan sebelum dan sesudah kontak dengan pasien dan lingkungan pasien\n- Pertahankan teknik aseptic pada pasien berisiko tinggi', '- Jelaskan tanda dan gejala infeksi\n- Ajarkan cara mencuci tangan dengan benar\n- Ajarkan etika batuk\n- Ajarkan cara memeriksa kondisi luka atau luka operasi\n- Anjurkan meningkatkan asupan nutrisi\n- Anjurkan meningkatkan asupan cairan', '- Kolaborasi pemberian imunisasi, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL),
	('810030be-07e7-11f1-8f82-0200ca9b8436', 'Regulasi Temperatur', '- Monitor suhu tubuh bayi sampai stabil (36,5 â€“ 37,5Â°C)\n- Monitor suhu tubuh anak tiap 2 jam, jika perlu\n- Monitor tekanan darah, frekuensi pernapasan dan nadi\n- Monitor warna dan suhu kulit\n- Monitor dan catat tanda dan gejala hipotermia atau hipertermia', '- Pasang alat pemantau suhu kontinu, jika perlu\n- Tingkatkan asupan cairan dan nutrisi yang adekuat\n- Bedong bayi segera setelah lahir untuk mencegah kehilangan panas\n- Masukkan bayi BBLR ke dalam plastic segera setelah lahir (mis: bahan polyethylene, polyurethane)\n- Gunakan topi bayi untuk mencegah kehilangan panas pada bayi baru lahir\n- Tempatkan bayi baru lahir di bawah radiant warmer\n- Pertahankan kelembaban incubator 50% atau lebih untuk mengurangi kehilangan panas karena proses evaporasi\n- Atur suhu incubator sesuai kebutuhan\n- Hangatkan terlebih dahulu bahan-bahan yang akan kontak dengan bayi (mis: selimut, kain bedongan, stetoskop)\n- Hindari meletakkan bayi di dekat jendela terbuka atau di area aliran pendingin ruangan atau kipas angin\n- Gunakan matras penghangat, selimut hangat, dan penghangat ruangan untuk menaikkan suhu tubuh, jika perlu\n- Gunakan Kasur pendingin, water circulating blankets, ice pack, atau gel pad dan intravascular cooling cathetherization untuk menurunkan suhu tubuh\n- Sesuaikan suhu lingkungan dengan kebutuhan pasien', '- Jelaskan cara pencegahan heat exhaustion dan heat stroke\n- Jelaskan cara pencegahan hipotermi karena terpapar udara dingin\n- Demonstrasikan Teknik perawatan metode kanguru (PMK) untuk bayi BBLR', '- Kolaborasi pemberian antipiretik, jika perlu', '2026-02-12 07:50:30', '2026-02-12 07:50:30', NULL);
INSERT INTO `list_slki` (`id`, `ekspetasi_kriteria_hasil`, `created_at`, `updated_at`, `deleted_at`) VALUES
	('f6ebccf5-07e4-11f1-8f82-0200ca9b8436', 'Bersihan Jalan Napas Meningkat\n- Batuk efektif meningkat\n- Produksi sputum menurun\n- Mengi menurun\n- Wheezing menurun\n- Mekonium (pada neonatus) menurun\n- Dispnea menurun\n- Ortopnea menurun\n- Sulit bicara menurun\n- Sianosis menurun\n- Gelisah menurun\n- Frekuensi napas membaik\n- Pola napas membaik', '2026-02-12 07:32:20', '2026-02-12 07:32:20', NULL),
	('f6ebcefb-07e4-11f1-8f82-0200ca9b8436', 'Pertukaran Gas Meningkat\n- Tingkat kesadaran meningkat\n- Dispnea menurun\n- Bunyi napas tambahan menurun\n- Takikardi menurun\n- Pusing menurun\n- Penglihatan kabur menurun\n- Diaphoresis menurun\n- Gelisah menurun\n- Napas cuping hidung menurun\n- PCO2 membaik\n- PO2 membaik\n- pH arteri membaik\n- Sianosis membaik\n- Pola napas membaik\n- Warna kulit membaik', '2026-02-12 07:32:20', '2026-02-12 07:32:20', NULL),
	('f6ebd00b-07e4-11f1-8f82-0200ca9b8436', 'Ventilasi Spontan Meningkat\n- Dispnea menurun\n- Penggunaan otot bantu napas menurun\n- Takikardi menurun\n- Gelisah menurn\n- Volume tidal membaik\n- PCO2 membaik\n- PO2 membaik', '2026-02-12 07:32:20', '2026-02-12 07:32:20', NULL),
	('f6ebd087-07e4-11f1-8f82-0200ca9b8436', 'Pola Napas Membaik\n- Dispnea menurun\n- Penggunaan otot bantu napas menurun\n- Pemanjangan fase ekspirasi menurun\n- Ortopnea menurun\n- Pernapsan pursed-lip menurun\n- Pernapsan cuping hidung menurun\n- Frekuensi napas membaik\n- Kedalaman napas membaik\n- Ekskursi dada membaik\n- Ventilasi semenit membaik\n- Kapsitas vital membaik\n- Diameter thoraks anterior-posterior membaik\n- Tekanan ekspirasi membaik\n- Tekanan inspirasi membaik', '2026-02-12 07:32:20', '2026-02-12 07:32:20', NULL),
	('f6ebd0e8-07e4-11f1-8f82-0200ca9b8436', 'Sirkulasi Spontan Meningkat\n- Tingkat kesadaran meningkat\n- Gambaran EKG aritmia menurun\n- Frekuensi nadi membaik\n- Tekanan darah membaik\n- Frekuensi napas membaik\n- Saturasi oksigen membaik\n- Suhu tubuh membaik\n- ETCO2 membaik\n- Output urin membaik', '2026-02-12 07:32:20', '2026-02-12 07:32:20', NULL),
	('f6ebd14a-07e4-11f1-8f82-0200ca9b8436', 'Curah Jantung Meningkat\n- Kekuatan nadi perifer meningkat\n- Ejection fraction (EF) meningkat\n- Palpitasi menurun\n- Bradikardi menurun\n- Takikardi menurun\n- Gambaran EKG aritmia menurun\n- Lelah menurun\n- Edema menurun\n- Distensi vena jugularis menurun\n- Dispnea menurun\n- Oliguria menurun\n- Pucat/ sianosis menurun\n- Paroximal nocturnal dyspnea (PND) menurun\n- Ortopnea menurun\n- Batuk menurun\n- Suara jantung S3 menurun\n- Suara jantung S4 menurun\n- Tekanan darah membaik\n- Pengisian kapiler membaik', '2026-02-12 07:32:20', '2026-02-12 07:32:20', NULL),
	('f6ebd1b0-07e4-11f1-8f82-0200ca9b8436', 'Perfusi Perifer Meningkat\n- Kekuatan nadi perifer meningkat\n- Penyembuhan luka meningkat\n- Sensasi meningkat\n- Warna kulit pucat menurun\n- Edema perifer menurun\n- Nyeri ekstermitas menurun\n- Parastesia menurun\n- Kelemahan otot menurun\n- Kram otot menurun\n- Bruit femoralis menurun\n- Nekrosis menurun\n- Pengisian kapiler membaik\n- Akral membaik\n- Turgor kulit membaik\n- Tekanan darah sitolik membaik\n-Tekanan darah diastolic membaik\n- Tekanan arteri rata-rata membaik\n- Indeks ankle-brachial membaik', '2026-02-12 07:32:20', '2026-02-12 07:32:20', NULL),
	('f6ebd207-07e4-11f1-8f82-0200ca9b8436', 'Curah Jantung Meningkat\n- Kekuatan nadi perifer meningkat\n- Ejection fraction (EF) meningkat\n- Palpitasi menurun\n- Bradikardi menurun\n- Takikardi menurun\n- Gambaran EKG aritmia menurun\n- Lelah menurun\n- Edema menurun\n- Distensi vena jugularis menurun\n- Dispnea menurun\n- Oliguria menurun\n- Pucat/ sianosis menurun\n- Paroximal nocturnal dyspnea (PND) menurun\n- Ortopnea menurun\n- Batuk menurun\n- Suara jantung S3 menurun\n- Suara jantung S4 menurun\n- Tekanan darah membaik\n- Pengisian kapiler membaik', '2026-02-12 07:32:20', '2026-02-12 07:32:20', NULL),
	('f6ebd2d8-07e4-11f1-8f82-0200ca9b8436', 'Tingkat Perdarahan Menurun\n- Membran mukosa lembab meningkat\n- Kelembapan kulit meningkat\n- Kognitif meningkat\n- Hemoptisis menurun\n- Hematemesis menurun\n- Hematuria menurun\n- Perdarahan anus menurun\n- Distensi abdomen menurun\n- Perdarahan vagina menurun\n- Perdarahan pasca operasi menurun\n- Hemoglobin membaik\n- Hematokrit membaik\n- Tekanan darah membaik\n- Frekuensi nadi membaik\n- Suhu tubuh membaik', '2026-02-12 07:32:20', '2026-02-12 07:32:20', NULL),
